  "c1t09": [{"type":"ecoute","consigne":"Écoute - Que se passe-t-il si on n'agit pas ?","audio":"Wenn wir jetzt nicht handeln, werden die Folgen des Klimawandels unumkehrbar sein.","options":["Rien ne changera","Le climat s'améliorera","Les conséquences seront irréversibles"],"correct":2,"explication":"« unumkehrbar » = irréversible. (texte : « Wenn wir jetzt nicht handeln, werden die Folgen des Klimawandels unumkehrbar sein. »)"},{"type":"ecoute","consigne":"Écoute - Quel probleme est evoque ?","audio":"Die Artenvielfalt nimmt durch die Umweltverschmutzung bedrohlich ab.","options":["La biodiversite diminue","Le tourisme augmente","Rien ne change"],"correct":0,"explication":"« Artenvielfalt ». (texte : « Die Artenvielfalt nimmt durch die Umweltverschmutzung bedrohlich ab. »)"},{"type":"ecoute","consigne":"Écoute - Quelle solution est proposee ?","audio":"Die Energiewende braucht grosse Investitionen, um klimaneutral zu werden.","options":["La transition energetique","Plus de pollution","Moins d'ecoles"],"correct":0,"explication":"« Energiewende » + « klimaneutral ». (texte : « Die Energiewende braucht grosse Investitionen, um klimaneutral zu werden. »)"}],
